from pathlib import Path

from docx import Document
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml import OxmlElement
from docx.oxml.ns import qn
from docx.shared import Cm, Pt
from docx.text.paragraph import Paragraph


DOCX = Path("KVR_Burunduk_Garage_full_report.docx")


def run_font(run, size=14, bold=False):
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(size)
    run.bold = bold


def format_body(paragraph):
    paragraph.style = paragraph.part.document.styles["Normal"]
    paragraph.paragraph_format.first_line_indent = Cm(1.25)
    paragraph.paragraph_format.left_indent = Cm(0)
    paragraph.paragraph_format.line_spacing = 1.5
    paragraph.paragraph_format.space_before = Pt(0)
    paragraph.paragraph_format.space_after = Pt(0)
    paragraph.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    for run in paragraph.runs:
        run_font(run)


def insert_after(paragraph, text):
    new_p = OxmlElement("w:p")
    paragraph._p.addnext(new_p)
    new_paragraph = Paragraph(new_p, paragraph._parent)
    new_paragraph.add_run(text)
    format_body(new_paragraph)
    return new_paragraph


def heading_map(doc):
    result = {}
    for i, paragraph in enumerate(doc.paragraphs):
        text = paragraph.text.strip()
        if paragraph.style.name.startswith("Heading") and text:
            result[text] = i
    return result


def insertion_anchor(doc, heading_text):
    headings = heading_map(doc)
    if heading_text not in headings:
        raise ValueError(f"Heading not found: {heading_text}")
    start = headings[heading_text]
    next_heading = len(doc.paragraphs)
    for i in range(start + 1, len(doc.paragraphs)):
        p = doc.paragraphs[i]
        if p.style.name.startswith("Heading") and p.text.strip():
            next_heading = i
            break
    idx = max(start, next_heading - 1)
    while idx > start and not doc.paragraphs[idx].text.strip():
        idx -= 1
    return doc.paragraphs[idx]


def add_block(doc, heading_text, paragraphs):
    anchor = insertion_anchor(doc, heading_text)
    for text in paragraphs:
        anchor = insert_after(anchor, text)


def apply_subheading_indents(doc):
    hmap = heading_map(doc)
    fourth_idx = hmap.get("4. ЕКОНОМІЧНИЙ РОЗДІЛ")
    if fourth_idx is None:
        fourth_idx = next(
            i for i, p in enumerate(doc.paragraphs)
            if p.style.name.startswith("Heading") and p.text.strip().startswith("4")
        )
    for i, paragraph in enumerate(doc.paragraphs):
        if i >= fourth_idx:
            break
        if paragraph.style.name in ("Heading 2", "Heading 3"):
            paragraph.paragraph_format.first_line_indent = Cm(1.25)
            paragraph.paragraph_format.left_indent = Cm(0)
            paragraph.alignment = WD_ALIGN_PARAGRAPH.LEFT
            paragraph.paragraph_format.line_spacing = 1.5
            paragraph.paragraph_format.space_before = Pt(0)
            paragraph.paragraph_format.space_after = Pt(0)
            for run in paragraph.runs:
                run_font(run, bold=True)


